def evaluate_position(board):
    """
    Evaluates a chess position and returns a numerical score indicating the advantage.

    Args:
        board: A representation of the chess board.  This could be a string in FEN notation,
               a list of lists representing the board, or a custom object.  For simplicity,
               we'll assume it's a list of lists, where each inner list represents a row,
               and each element in the inner list is a string representing the piece
               (e.g., 'P' for white pawn, 'p' for black pawn, 'R' for white rook, etc.).
               Empty squares are represented by '.'.

    Returns:
        A numerical score.  Positive values indicate an advantage for white,
        negative values indicate an advantage for black.
    """

    piece_values = {
        'P': 1, 'N': 3, 'B': 3, 'R': 5, 'Q': 9, 'K': 0,  # White pieces
        'p': -1, 'n': -3, 'b': -3, 'r': -5, 'q': -9, 'k': 0   # Black pieces
    }

    white_material = 0
    black_material = 0
    white_controlled_squares = 0
    black_controlled_squares = 0
    white_mobility = 0
    black_mobility = 0

    for row in range(8):
        for col in range(8):
            piece = board[row][col]
            if piece in piece_values:
                if piece.isupper():
                    white_material += piece_values[piece]
                else:
                    black_material += piece_values[piece]

            # Simplified controlled squares (just count pieces around)
            if piece != '.':
                for dr in [-1, 0, 1]:
                    for dc in [-1, 0, 1]:
                        if dr == 0 and dc == 0:
                            continue
                        new_row = row + dr
                        new_col = col + dc
                        if 0 <= new_row < 8 and 0 <= new_col < 8:
                            if piece.isupper():
                                white_controlled_squares += 0.1  # Small bonus
                            else:
                                black_controlled_squares += 0.1

            # Simplified mobility (count empty squares around)
            if piece in ['N', 'n']:
                moves = [(-2, -1), (-2, 1), (-1, -2), (-1, 2), (1, -2), (1, 2), (2, -1), (2, 1)]
                for dr, dc in moves:
                    new_row = row + dr
                    new_col = col + dc
                    if 0 <= new_row < 8 and 0 <= new_col < 8 and board[new_row][new_col] == '.':
                        if piece.isupper():
                            white_mobility += 0.05
                        else:
                            black_mobility += 0.05

    # Central control (more valuable)
    central_squares = [(3, 3), (3, 4), (4, 3), (4, 4)]
    for row, col in central_squares:
        piece = board[row][col]
        if piece != '.':
            if piece.isupper():
                white_controlled_squares += 0.2
            else:
                black_controlled_squares += 0.2

    evaluation = (white_material - black_material) + \
                 (white_controlled_squares - black_controlled_squares) + \
                 (white_mobility - black_mobility)

    return evaluation

